struct Restaurant {
    string city;
    int score;
    int index;
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<Restaurant> a(n);
    for (int i = 0; i < n; ++i) {
        cin >> a[i].city >> a[i].score;
        a[i].index = i + 1;
    }
    sort(a.begin(), a.end(), [](const Restaurant& lhs, const Restaurant& rhs) {
        if (lhs.city != rhs.city) return lhs.city < rhs.city;
        return lhs.score > rhs.score;
    });
    for (const auto& r : a) cout << r.index << '\n';
    return 0;
}

