    int n, m;
    cin >> n >> m;
    vector<vector<int>> lamps(m);
    for (int i = 0; i < m; ++i) {
        int k;
        cin >> k;
        lamps[i].resize(k);
        for (int& s : lamps[i]) {
            cin >> s;
            --s;
        }
    }
    vector<int> p(m);
    for (int& x : p) cin >> x;

    int ans = 0;
    for (int mask = 0; mask < (1 << n); ++mask) {
        bool ok = true;
