const long long MOD = 1000000007LL;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, m;
    cin >> n >> m;
    vector<int> broken(n + 1, 0);
    for (int i = 0; i < m; ++i) {
        int a;
        cin >> a;
        broken[a] = 1;
    }
    vector<long long> dp(n + 1, 0);
    dp[0] = 1;
    for (int i = 1; i <= n; ++i) {
        if (broken[i]) continue;
        dp[i] = dp[i - 1];
        if (i >= 2) dp[i] = (dp[i] + dp[i - 2]) % MOD;
    }
    cout << dp[n] << '\n';
    return 0;
}

