int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, d;
    cin >> n >> d;
    vector<vector<int>> x(n, vector<int>(d));
    for (auto& p : x) for (int& v : p) cin >> v;
    int ans = 0;
    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            int dist2 = 0;
            for (int k = 0; k < d; ++k) {
                int diff = x[i][k] - x[j][k];
                dist2 += diff * diff;
            }
            int root = (int)(sqrt(dist2) + 0.5);
            if (root * root == dist2) ++ans;
        }
    }
    cout << ans << '\n';
    return 0;
}

