int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    string s;
    cin >> s;
    int n = (int)s.size();
    vector<int> ans(n, 0);
    int i = 0;
    while (i < n) {
        int rStart = i;
        while (i < n && s[i] == 'R') ++i;
        int rCount = i - rStart;
        int lStart = i;
        while (i < n && s[i] == 'L') ++i;
        int lCount = i - lStart;
        if (rCount > 0 && lCount > 0) {
            int leftPos = lStart - 1;
            int rightPos = lStart;
            ans[leftPos] = (rCount + 1) / 2 + lCount / 2;
            ans[rightPos] = rCount / 2 + (lCount + 1) / 2;
        }
    }
    for (int j = 0; j < n; ++j) {
        if (j) cout << ' ';
        cout << ans[j];
    }
    cout << '\n';
    return 0;
}

