int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, m;
    cin >> n >> m;
    priority_queue<long long> pq;
    for (int i = 0; i < n; ++i) {
        long long a;
        cin >> a;
        pq.push(a);
    }
    while (m--) {
        long long x = pq.top();
        pq.pop();
        pq.push(x / 2);
    }
    long long ans = 0;
    while (!pq.empty()) {
        ans += pq.top();
        pq.pop();
    }
    cout << ans << '\n';
    return 0;
}

