#include <map>
#include <numeric>
#include <queue>
#include <set>
#include <string>
#include <tuple>
#include <utility>
#include <vector>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<double> x(n), y(n);
    for (int i = 0; i < n; ++i) cin >> x[i] >> y[i];
    vector<int> p(n);
    iota(p.begin(), p.end(), 0);
    double total = 0.0;
    long long count = 0;
    do {
        for (int i = 0; i + 1 < n; ++i) {
            double dx = x[p[i]] - x[p[i + 1]];
            double dy = y[p[i]] - y[p[i + 1]];
            total += sqrt(dx * dx + dy * dy);
        }
        ++count;
    } while (next_permutation(p.begin(), p.end()));
    cout << fixed << setprecision(10) << total / count << '\n';
    return 0;
}
